package com.example.enterpriseapp.service;

import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.repository.AppUserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.util.List;

@Service
@Transactional
public class UserService {
    private final AppUserRepository appUserRepository;

    public UserService(AppUserRepository appUserRepository) {
        this.appUserRepository = appUserRepository;
    }

    public AppUser createUser(AppUser user) {
        if (appUserRepository.existsByUsername(user.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (appUserRepository.existsByEmail(user.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }
        return appUserRepository.save(user);
    }

    @Transactional(readOnly = true)
    public AppUser getUser(Long id) {
        return appUserRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("User not found: " + id));
    }

    @Transactional(readOnly = true)
    public List<AppUser> getAllUsers() {
        return appUserRepository.findAll();
    }

    public AppUser updateUser(Long id, AppUser request) {
        AppUser existing = getUser(id);
        if (request.getUsername() != null && !request.getUsername().equals(existing.getUsername())) {
            if (appUserRepository.existsByUsername(request.getUsername())) {
                throw new IllegalArgumentException("Username already exists");
            }
            existing.setUsername(request.getUsername());
        }
        if (request.getEmail() != null && !request.getEmail().equals(existing.getEmail())) {
            if (appUserRepository.existsByEmail(request.getEmail())) {
                throw new IllegalArgumentException("Email already exists");
            }
            existing.setEmail(request.getEmail());
        }
        if (request.getPasswordHash() != null) {
            existing.setPasswordHash(request.getPasswordHash());
        }
        existing.setActive(request.isActive());
        return appUserRepository.save(existing);
    }

    public void deactivateUser(Long id) {
        AppUser existing = getUser(id);
        existing.setActive(false);
        appUserRepository.save(existing);
    }
}

package com.example.enterpriseapp.service;

import com.example.enterpriseapp.domain.AppTransaction;
import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.repository.AppTransactionRepository;
import com.example.enterpriseapp.repository.AppUserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.math.BigDecimal;
import java.util.List;

@Service
@Transactional
public class TransactionService {
    private final AppTransactionRepository transactionRepository;
    private final AppUserRepository userRepository;

    public TransactionService(AppTransactionRepository transactionRepository, AppUserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    public AppTransaction createTransaction(AppTransaction transaction) {
        AppUser user = userRepository.findById(transaction.getUserId())
                .orElseThrow(() -> new EntityNotFoundException("User not found: " + transaction.getUserId()));
        if (!user.isActive()) {
            throw new IllegalStateException("User is inactive");
        }
        if (transaction.getAmount() == null || transaction.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new IllegalArgumentException("Amount must be greater than zero");
        }
        if (transaction.getCurrency() == null || transaction.getCurrency().isBlank()) {
            throw new IllegalArgumentException("Currency is required");
        }
        if (transaction.getStatus() == null || transaction.getStatus().isBlank()) {
            transaction.setStatus("PENDING");
        }
        return transactionRepository.save(transaction);
    }

    @Transactional(readOnly = true)
    public AppTransaction getTransaction(Long id) {
        return transactionRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found: " + id));
    }

    @Transactional(readOnly = true)
    public List<AppTransaction> getTransactionsByUser(Long userId) {
        return transactionRepository.findByUserIdOrderByCreatedAtDesc(userId);
    }

    public AppTransaction updateTransactionStatus(Long id, String status) {
        AppTransaction tx = getTransaction(id);
        tx.setStatus(status);
        return transactionRepository.save(tx);
    }

    public void deleteTransaction(Long id) {
        transactionRepository.deleteById(id);
    }
}

package com.example.enterpriseapp.web;

